To develop a Checkers (Draughts) game, we need to create several classes and methods to handle the game logic. Below is a step-by-step approach to implement these classes and methods.

### Step 1: Define the Board Class

We will start by defining a `Board` class that represents the checkers board.

```python
class Board:
    def __init__(self):
        self.board = []
        self.initialize_board()

    def initialize_board(self):
        # Initialize an 8x8 board with pieces in the starting positions
        for i in range(8):
            row = []
            for j in range(8):
                if (i + j) % 2 == 1:
                    if i < 3:
                        row.append('b')  # Black pieces at the bottom rows
                    elif i > 4:
                        row.append('r')  # Red pieces at the top rows
                    else:
                        row.append(' ')  # Empty squares
                else:
                    row.append(' ')
            self.board.append(row)

    def print_board(self):
        for row in self.board:
            print(" ".join(row))
```

### Step 2: Define the Piece Class

Next, we will define a `Piece` class to represent individual pieces.

```python
class Piece:
    def __init__(self, color):
        self.color = color
        self.king = False

    def king_me(self):
        self.king = True

    def is_king(self):
        return self.king

    def get_color(self):
        return self.color
```

### Step 3: Define the Game Class

Finally, we will define a `Game` class that encapsulates the game logic.

```python
class Game:
    def __init__(self):
        self.board = Board()
        self.current_player = 'r'

    def switch_turn(self):
        self.current_player = 'b' if self.current_player == 'r' else 'r'

    def move_piece(self, start_pos, end_pos):
        row_start, col_start = start_pos
        row_end, col_end = end_pos

        # Check if the move is valid
        if abs(row_start - row_end) not in [1, 2] or abs(col_start - col_end) != 1:
            return False

        piece = self.board.board[row_start][col_start]

        if piece == ' ' or piece.get_color() != self.current_player:
            return False

        # Handle capturing
        if abs(row_start - row_end) == 2:
            mid_row, mid_col = (row_start + row_end) // 2, (col_start + col_end) // 2
            captured_piece = self.board.board[mid_row][mid_col]
            if captured_piece != ' ' and captured_piece.get_color() != piece.get_color():
                self.board.board[mid_row][mid_col] = ' '
            else:
                return False

        # Move the piece
        self.board.board[row_end][col_end] = Piece(piece.get_color())
        self.board.board[row_start][col_start] = ' '

        # Check if the piece should be kinged
        if (self.current_player == 'r' and row_end == 0) or (self.current_player == 'b' and row_end == 7):
            self.board.board[row_end][col_end].king_me()

        return True

    def check_winner(self):
        # Check if the game is over
        pieces = [cell for row in self.board.board for cell in row if isinstance(cell, Piece)]
        red_pieces = sum(1 for piece in pieces if piece.get_color() == 'r')
        black_pieces = sum(1 for piece in pieces if piece.get_color() == 'b')

        if red_pieces == 0:
            return 'Black wins'
        elif black_pieces == 0:
            return 'Red wins'
        else:
            return None
```

### Step 4: Implement the Main Function

Now, let's implement the main function to handle user input and game loop.

```python
def main():
    game = Game()

    while True:
        game.board.print_board()
        print(f"Player {game.current_player}'s turn")

        start_pos = input("Enter the starting position (e.g., 3 4): ").split()
        end_pos = input("Enter the ending position (e.g., 2 5): ").split()

        if len(start_pos) != 2 or len(end_pos) != 2:
            print("Invalid input. Please enter positions in the format: row column")
            continue

        start_row, start_col = int(start_pos[0]), int(start_pos[1])
        end_row, end_col = int(end_pos[0]), int(end_pos[1])

        if game.move_piece((start_row, start_col), (end_row, end_col)):
            winner = game.check_winner()
            if winner:
                print(f"Game over: {winner}")
                break
            game.switch_turn()
        else:
            print("Invalid move. Please try again.")

if __name__ == "__main__":
    main()
```

